// Protected user info route (fetches from OIDC provider)
app.get('/auth/userinfo', isAuthenticated, async (req, res) => {
  try {
    if (!req.session.tokens || !req.session.tokens.accessToken) {
      return res.status(401).json({ error: 'No access token available' });
    }

    // Check if access token has expired
    if (Date.now() > req.session.tokens.expiresAt) {
      return res.status(401).json({ error: 'Access token has expired. Please re-authenticate.' });
    }

    const userInfoResponse = await axios.get(oidcConfig.userInfoEndpoint, {
      headers: {
        Authorization: `${req.session.tokens.tokenType} ${req.session.tokens.accessToken}`,
      },
      timeout: 10000,
    });

    res.json({
      source: 'userinfo_endpoint',
      data: userInfoResponse.data,
    });
  } catch (err) {
    console.error('UserInfo endpoint error:', err.message);
    res.status(500).json({ error: 'Failed to fetch user info' });
  }
});

// Logout route
app.get('/auth/logout', (req, res) => {
  const user = req.session.user;

  req.session.destroy((err) => {
    if (err) {
      console.error('Session destruction error:', err);
      return res.status(500).json({ error: 'Logout failed' });
    }

    res.clearCookie('connect.sid');

    if (user) {
      console.log(`User logged out: ${user.sub} (${user.email})`);
    }

    res.json({ message: 'Successfully logged out' });
  });
});

